import { useState, useEffect, useRef } from 'react';
import { Link, useLocation, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { Menu, X, Home, Building2, Calculator, Phone, LogIn, User, LogOut, Shield } from 'lucide-react';

const Navbar = () => {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);
  const [isDropdownOpen, setIsDropdownOpen] = useState(false);
  const location = useLocation();
  const navigate = useNavigate();
  const { user, logout, isAuthenticated } = useAuth();
  const dropdownRef = useRef(null);

  useEffect(() => {
    const handleClickOutside = (event) => {
      if (dropdownRef.current && !dropdownRef.current.contains(event.target)) {
        setIsDropdownOpen(false);
      }
    };
    document.addEventListener('mousedown', handleClickOutside);
    return () => document.removeEventListener('mousedown', handleClickOutside);
  }, []);

  const handleLogout = () => {
    logout();
    navigate('/');
    setIsDropdownOpen(false);
  };

  const navLinks = [
    { name: 'Home', path: '/', icon: Home },
    { name: 'Properties', path: '/projects', icon: Building2 },
    { name: 'EMI Calculator', path: '/emi-calculator', icon: Calculator },
    { name: 'Contact', path: '/contact', icon: Phone },
  ];

  const isAdmin = user?.email === 'admin@swabhagya.com' || user?.role === 'admin';

  return (
    <nav className="bg-[#4A2C2C] py-4 fixed top-0 w-full z-50 shadow-lg">
      <div className="container-custom">
        <div className="flex justify-between items-center">
          <Link to="/" className="flex items-center gap-2">
            <div className="w-10 h-10 bg-[#D3504A] rounded-lg flex items-center justify-center">
              <span className="text-white font-bold text-xl">S</span>
            </div>
            <div>
              <span className="text-white font-bold text-xl tracking-wide">SWABHAGYA</span>
              <span className="text-[#FFDC76] font-bold text-xl"> REALTY</span>
            </div>
          </Link>
          
          <div className="hidden md:flex items-center gap-8">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className={`flex items-center gap-2 transition-all duration-300 font-medium ${
                  location.pathname === link.path 
                    ? 'text-[#FFDC76]' 
                    : 'text-white/80 hover:text-[#FFDC76]'
                }`}
              >
                <link.icon size={18} />
                {link.name}
              </Link>
            ))}
            
            <Link
              to="/admin/login"
              className="flex items-center gap-2 bg-[#D3504A]/20 px-3 py-2 rounded-lg text-white/80 hover:text-white hover:bg-[#D3504A]/30 transition"
            >
              <Shield size={16} />
              Admin
            </Link>
            
            <a 
              href="https://wa.me/919272560005?text=Hi%20Swabhagya%20Realty%2C%20I'm%20interested%20in%20your%20properties"
              target="_blank"
              rel="noopener noreferrer"
              className="bg-[#D3504A] text-white px-5 py-2 rounded-full hover:bg-opacity-90 transition font-semibold"
            >
              Enquire Now
            </a>
            
            {isAuthenticated ? (
              <div className="relative" ref={dropdownRef}>
                <button
                  onClick={() => setIsDropdownOpen(!isDropdownOpen)}
                  className="flex items-center gap-2 bg-[#D3504A]/20 px-4 py-2 rounded-full text-white hover:bg-[#D3504A]/30 transition"
                >
                  <User size={18} />
                  <span>{user?.name?.split(' ')[0]}</span>
                  <span className="text-xs">▼</span>
                </button>
                
                {isDropdownOpen && (
                  <div className="absolute right-0 mt-2 w-48 bg-white rounded-lg shadow-xl py-2 z-50">
                    <Link
                      to="/dashboard"
                      onClick={() => setIsDropdownOpen(false)}
                      className="flex items-center gap-3 px-4 py-2 text-gray-700 hover:bg-gray-100 transition"
                    >
                      <User size={16} />
                      Dashboard
                    </Link>
                    {isAdmin && (
                      <Link
                        to="/admin/dashboard"
                        onClick={() => setIsDropdownOpen(false)}
                        className="flex items-center gap-3 px-4 py-2 text-gray-700 hover:bg-gray-100 transition"
                      >
                        <Shield size={16} />
                        Admin Panel
                      </Link>
                    )}
                    <hr className="my-1" />
                    <button
                      onClick={handleLogout}
                      className="flex items-center gap-3 w-full text-left px-4 py-2 text-red-600 hover:bg-gray-100 transition"
                    >
                      <LogOut size={16} />
                      Logout
                    </button>
                  </div>
                )}
              </div>
            ) : (
              <Link
                to="/login"
                className="flex items-center gap-2 bg-[#D3504A]/20 px-4 py-2 rounded-full text-white hover:bg-[#D3504A]/30 transition"
              >
                <LogIn size={18} />
                Login / Signup
              </Link>
            )}
          </div>
          
          <button 
            className="md:hidden text-white"
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
          >
            {isMobileMenuOpen ? <X size={24} /> : <Menu size={24} />}
          </button>
        </div>
        
        {isMobileMenuOpen && (
          <div className="md:hidden mt-4 bg-[#4A2C2C] rounded-lg p-4 border border-[#FFDC76]/20">
            {navLinks.map((link) => (
              <Link
                key={link.path}
                to={link.path}
                className="flex items-center gap-3 py-3 text-white/80 hover:text-[#FFDC76] transition"
                onClick={() => setIsMobileMenuOpen(false)}
              >
                <link.icon size={18} />
                {link.name}
              </Link>
            ))}
            
            <Link
              to="/admin/login"
              className="flex items-center gap-3 py-3 text-white/80 hover:text-[#FFDC76] transition"
              onClick={() => setIsMobileMenuOpen(false)}
            >
              <Shield size={18} /> Admin
            </Link>
            
            <a 
              href="https://wa.me/919272560005?text=Hi%20Swabhagya%20Realty%2C%20I'm%20interested%20in%20your%20properties"
              target="_blank"
              rel="noopener noreferrer"
              className="block w-full bg-[#D3504A] text-white px-5 py-2 rounded-full text-center font-semibold mt-3"
              onClick={() => setIsMobileMenuOpen(false)}
            >
              Enquire Now
            </a>
            
            <div className="border-t border-white/20 pt-3 mt-3">
              {isAuthenticated ? (
                <>
                  <Link
                    to="/dashboard"
                    className="flex items-center gap-3 py-3 text-white/80 hover:text-[#FFDC76]"
                    onClick={() => setIsMobileMenuOpen(false)}
                  >
                    <User size={18} /> Dashboard
                  </Link>
                  {isAdmin && (
                    <Link
                      to="/admin/dashboard"
                      className="flex items-center gap-3 py-3 text-white/80 hover:text-[#FFDC76]"
                      onClick={() => setIsMobileMenuOpen(false)}
                    >
                      <Shield size={18} /> Admin Panel
                    </Link>
                  )}
                  <button
                    onClick={handleLogout}
                    className="flex items-center gap-3 py-3 text-red-400 hover:text-red-300 w-full"
                  >
                    <LogOut size={18} /> Logout
                  </button>
                </>
              ) : (
                <Link
                  to="/login"
                  className="flex items-center gap-3 py-3 text-[#FFDC76] font-semibold"
                  onClick={() => setIsMobileMenuOpen(false)}
                >
                  <LogIn size={18} /> Login / Signup
                </Link>
              )}
            </div>
          </div>
        )}
      </div>
    </nav>
  );
};

export default Navbar;
